Missing `child.on('error', ...)` handling. If spawning `node` fails (ENOENT, permission, etc.), the promise will never settle. Add an `error` listener that rejects.

```suggestion
    const promise = new Promise<string>((resolve, reject) => {
      child.on('error', reject);
      child.on('close', (code: number | null, signal: NodeJS.Signals | null) => {
        if (code === 0) {
          this._lastRunStdout = stdout;
          let result = stdout;
          if (stderr) result += `\n\nStdErr:\n${stderr}`;
          resolve(result);
        } else {
          const extra = signal ? ` (signal: ${signal})` : '';
          reject(new Error(`Process exited with code ${code}${extra}:\n${stderr}`));
        }
      });
    });
```

