		// Fallback for older connserver versions that don't output JWT status line
		// Assume the old behavior: write JWT token unconditionally
		conn.Infof(ctx, "timeout reading jwt status line, assuming old connserver behavior\n")
		_, err = fmt.Fprintf(stdinPipe, "%s\n", jwtToken)
		if err != nil {
			sshSession.Close()
			return false, clientVersion, "", fmt.Errorf("failed to write JWT token: %w", err)
		}
	} else {
